#include <iostream>
#include <vector>
#include <string>
#include <sstream>

// The calculateGCD function would be included here from the user's code.

int calculateGCD(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    std::vector<std::pair<std::string, std::string>> tests = {
        {"48 18", "6"},
        {"-48 18", "6"},
        {"48 -18", "6"},
        {"-48 -18", "6"},
        {"0 0", "0"}
    };

    for (const auto& test : tests) {
        std::stringstream ss(test.first);
        int a, b;
        ss >> a >> b;
        int result = calculateGCD(a, b);
        std::cout << "Input: (" << a << ", " << b << "), Expected: " << test.second << ", Got: " << result << std::endl;
    }
    return 0;
}
